-- Initial production catalog. Idempotent and safe to rerun.
on conflict(slug) do update set name=excluded.name,description=excluded.description,is_active=excluded.is_active,sort_order=excluded.sort_order;

on conflict(slug) do update set name=excluded.name,short_description=excluded.short_description,long_description=excluded.long_description,price=excluded.price,currency=excluded.currency,category_id=excluded.category_id,status=excluded.status,is_featured=excluded.is_featured,delivery_type=excluded.delivery_type,features=excluded.features,includes=excluded.includes,published_at=coalesce(public.products.published_at,excluded.published_at);

on conflict(slug) do update set name=excluded.name,short_description=excluded.short_description,long_description=excluded.long_description,price_from=excluded.price_from,currency=excluded.currency,status=excluded.status,is_featured=excluded.is_featured,features=excluded.features,published_at=coalesce(public.services.published_at,excluded.published_at);
